  "root_cause": "The filter does not return after handling the unauthorized case, allowing the request to proceed to the target resource even when the user is not authenticated. Additionally, it uses a client-side redirect via JavaScript instead of a proper server-side redirect.",
  "refactoring": "Add a return statement after writing the redirect script to prevent further processing. Replace the JavaScript redirect with a proper HTTP redirect using response.sendRedirect(). Ensure the response is committed before returning.",
  "corrected_code": "package org.example.app.filter;

import javax.servlet.*;
import javax.servlet.annotation.WebFilter;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;

@WebFilter(filterName = "Sample023", urlPatterns = {"/main.jsp", "/user/*", "/role/*"})
public class Sample023 implements Filter {

    public void destroy() {
    }

    public void doFilter(ServletRequest req, ServletResponse resp, FilterChain chain) throws ServletException, IOException {
        HttpServletRequest request = (HttpServletRequest) req;
        HttpServletResponse response = (HttpServletResponse) resp;

        String loginname = (String) request.getSession().getAttribute("yonghu");
        if (loginname == null) {
            String loginUrl = request.getContextPath() + "/login.jsp";
            response.sendRedirect(loginUrl);
            return; // Important: stop further processing
        }
        chain.doFilter(req, resp);
    }

    public void init(FilterConfig config) throws ServletException {
    }
}"
}
